  const allErrors: BrowserError[] = [];
  const allWarnings: BrowserError[] = [];

  test.afterAll(async () => {
    if (allErrors.length > 0 || allWarnings.length > 0) {
      console.log('\n');
      console.log('╔' + '═'.repeat(78) + '╗');
      console.log('║' + ' '.repeat(25) + 'FINAL ERROR SUMMARY' + ' '.repeat(34) + '║');
